/**
 * Constants used throughout the stroke generation algorithm.
 * @internal
 */

const { PI } = Math

/**
 * Rate of change for simulated pressure.
 * Controls how quickly pressure changes based on drawing velocity.
 * Higher values make pressure more responsive to speed changes.
 */
export const RATE_OF_PRESSURE_CHANGE = 0.275

/**
 * PI with a tiny offset to fix browser rendering artifacts.
 * Some browsers render strokes incorrectly when using exact PI.
 */
export const FIXED_PI = PI + 0.0001

/**
 * Number of segments for rounded start caps.
 */
export const START_CAP_SEGMENTS = 13

/**
 * Number of segments for rounded end caps.
 * Higher than start caps for smoother appearance at stroke endings.
 */
export const END_CAP_SEGMENTS = 29

/**
 * Number of segments for sharp corner caps.
 */
export const CORNER_CAP_SEGMENTS = 13

/**
 * Pixels to skip at the end of a stroke to reduce noise.
 */
export const END_NOISE_THRESHOLD = 3

/**
 * Minimum interpolation factor for streamline.
 * Used when streamline is at maximum (1.0).
 */
export const MIN_STREAMLINE_T = 0.15

/**
 * Range for interpolation factor calculation.
 * Added to MIN_STREAMLINE_T based on (1 - streamline).
 */
export const STREAMLINE_T_RANGE = 0.85

/**
 * Minimum stroke radius to prevent invisible strokes.
 */
export const MIN_RADIUS = 0.01

/**
 * Default pressure for the first point of a stroke.
 * Lower than subsequent points to prevent fat starts,
 * since drawn lines almost always start slow.
 */
export const DEFAULT_FIRST_PRESSURE = 0.25

/**
 * Default pressure for subsequent points when no pressure is provided.
 */
export const DEFAULT_PRESSURE = 0.5

/**
 * Unit offset vector used as placeholder for initial vector
 * and for creating a second point when only one point is provided.
 */
export const UNIT_OFFSET: [number, number] = [1, 1]
/**
 * Compute a radius based on the pressure.
 * @param size
 * @param thinning
 * @param pressure
 * @param easing
 * @internal
 */
export function getStrokeRadius(
  size: number,
  thinning: number,
  pressure: number,
  easing: (t: number) => number = (t) => t
) {
  return size * easing(0.5 - thinning * (0.5 - pressure))
}
import { RATE_OF_PRESSURE_CHANGE } from './constants'

const { min } = Math

/**
 * Simulate pressure based on the distance between points and stroke size.
 * This creates a natural-looking pressure effect based on drawing velocity.
 *
 * @param prevPressure The previous pressure value
 * @param distance The distance from the previous point
 * @param size The base stroke size
 * @returns The simulated pressure value (0-1)
 * @internal
 */
export function simulatePressure(
  prevPressure: number,
  distance: number,
  size: number
): number {
  // Speed of change - how fast should the pressure be changing?
  const sp = min(1, distance / size)
  // Rate of change - how much of a change is there?
  const rp = min(1, 1 - sp)
  // Accelerate the pressure
  return min(
    1,
    prevPressure + (rp - prevPressure) * (sp * RATE_OF_PRESSURE_CHANGE)
  )
}
import type { Vec2 } from './types'

/**
 * Negate a vector.
 * @param A
 * @internal
 */
export function neg(A: Vec2): Vec2 {
  return [-A[0], -A[1]]
}

/**
 * Add vectors.
 * @param A
 * @param B
 * @internal
 */
export function add(A: Vec2, B: Vec2): Vec2 {
  return [A[0] + B[0], A[1] + B[1]]
}

/**
 * Add vectors into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @param B
 * @internal
 */
export function addInto(out: Vec2, A: Vec2, B: Vec2): Vec2 {
  out[0] = A[0] + B[0]
  out[1] = A[1] + B[1]
  return out
}

/**
 * Subtract vectors.
 * @param A
 * @param B
 * @internal
 */
export function sub(A: Vec2, B: Vec2): Vec2 {
  return [A[0] - B[0], A[1] - B[1]]
}

/**
 * Subtract vectors into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @param B
 * @internal
 */
export function subInto(out: Vec2, A: Vec2, B: Vec2): Vec2 {
  out[0] = A[0] - B[0]
  out[1] = A[1] - B[1]
  return out
}

/**
 * Vector multiplication by scalar
 * @param A
 * @param n
 * @internal
 */
export function mul(A: Vec2, n: number): Vec2 {
  return [A[0] * n, A[1] * n]
}

/**
 * Vector multiplication by scalar into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @param n
 * @internal
 */
export function mulInto(out: Vec2, A: Vec2, n: number): Vec2 {
  out[0] = A[0] * n
  out[1] = A[1] * n
  return out
}

/**
 * Vector division by scalar.
 * @param A
 * @param n
 * @internal
 */
export function div(A: Vec2, n: number): Vec2 {
  return [A[0] / n, A[1] / n]
}

/**
 * Perpendicular rotation of a vector A
 * @param A
 * @internal
 */
export function per(A: Vec2): Vec2 {
  return [A[1], -A[0]]
}

/**
 * Perpendicular rotation into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @internal
 */
export function perInto(out: Vec2, A: Vec2): Vec2 {
  const temp = A[0]
  out[0] = A[1]
  out[1] = -temp
  return out
}

/**
 * Dot product
 * @param A
 * @param B
 * @internal
 */
export function dpr(A: Vec2, B: Vec2): number {
  return A[0] * B[0] + A[1] * B[1]
}

/**
 * Get whether two vectors are equal.
 * @param A
 * @param B
 * @internal
 */
export function isEqual(A: Vec2, B: Vec2): boolean {
  return A[0] === B[0] && A[1] === B[1]
}

/**
 * Length of the vector
 * @param A
 * @internal
 */
export function len(A: Vec2): number {
  return Math.hypot(A[0], A[1])
}

/**
 * Length of the vector squared
 * @param A
 * @internal
 */
export function len2(A: Vec2): number {
  return A[0] * A[0] + A[1] * A[1]
}

/**
 * Dist length from A to B squared (inlined for performance).
 * @param A
 * @param B
 * @internal
 */
export function dist2(A: Vec2, B: Vec2): number {
  const dx = A[0] - B[0]
  const dy = A[1] - B[1]
  return dx * dx + dy * dy
}

/**
 * Get normalized / unit vector.
 * @param A
 * @internal
 */
export function uni(A: Vec2): Vec2 {
  return div(A, len(A))
}

/**
 * Dist length from A to B
 * @param A
 * @param B
 * @internal
 */
export function dist(A: Vec2, B: Vec2): number {
  return Math.hypot(A[1] - B[1], A[0] - B[0])
}

/**
 * Mean between two vectors or mid vector between two vectors
 * @param A
 * @param B
 * @internal
 */
export function med(A: Vec2, B: Vec2): Vec2 {
  return mul(add(A, B), 0.5)
}

/**
 * Rotate a vector around another vector by r (radians)
 * @param A vector
 * @param C center
 * @param r rotation in radians
 * @internal
 */
export function rotAround(A: Vec2, C: Vec2, r: number): Vec2 {
  const s = Math.sin(r)
  const c = Math.cos(r)

  const px = A[0] - C[0]
  const py = A[1] - C[1]

  const nx = px * c - py * s
  const ny = px * s + py * c

  return [nx + C[0], ny + C[1]]
}

/**
 * Rotate a vector around another vector by r (radians) into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A vector
 * @param C center
 * @param r rotation in radians
 * @internal
 */
export function rotAroundInto(out: Vec2, A: Vec2, C: Vec2, r: number): Vec2 {
  const s = Math.sin(r)
  const c = Math.cos(r)

  const px = A[0] - C[0]
  const py = A[1] - C[1]

  const nx = px * c - py * s
  const ny = px * s + py * c

  out[0] = nx + C[0]
  out[1] = ny + C[1]
  return out
}

/**
 * Interpolate vector A to B with a scalar t
 * @param A
 * @param B
 * @param t scalar
 * @internal
 */
export function lrp(A: Vec2, B: Vec2, t: number): Vec2 {
  return add(A, mul(sub(B, A), t))
}

/**
 * Interpolate vector A to B with a scalar t into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @param B
 * @param t scalar
 * @internal
 */
export function lrpInto(out: Vec2, A: Vec2, B: Vec2, t: number): Vec2 {
  const dx = B[0] - A[0]
  const dy = B[1] - A[1]
  out[0] = A[0] + dx * t
  out[1] = A[1] + dy * t
  return out
}

/**
 * Project a point A in the direction B by a scalar c
 * @param A
 * @param B
 * @param c
 * @internal
 */
export function prj(A: Vec2, B: Vec2, c: number): Vec2 {
  return add(A, mul(B, c))
}

/**
 * Project a point A in the direction B by a scalar c into an existing output vector (allocation-free).
 * @param out Output vector to mutate
 * @param A
 * @param B
 * @param c
 * @internal
 */
export function prjInto(out: Vec2, A: Vec2, B: Vec2, c: number): Vec2 {
  out[0] = A[0] + B[0] * c
  out[1] = A[1] + B[1] * c
  return out
}
import {
  CORNER_CAP_SEGMENTS,
  END_CAP_SEGMENTS,
  END_NOISE_THRESHOLD,
  FIXED_PI,
  MIN_RADIUS,
  START_CAP_SEGMENTS,
} from './constants'
import { getStrokeRadius } from './getStrokeRadius'
import { simulatePressure } from './simulatePressure'
import type { StrokeOptions, StrokePoint, Vec2 } from './types'
import {
  add,
  addInto,
  dist2,
  dpr,
  lrpInto,
  mul,
  mulInto,
  neg,
  per,
  perInto,
  prj,
  rotAround,
  rotAroundInto,
  sub,
  subInto,
  uni,
} from './vec'

// Scratch buffers for allocation-free hot loop calculations
const _offset: Vec2 = [0, 0]
const _tl: Vec2 = [0, 0]
const _tr: Vec2 = [0, 0]

/**
 * Draw a dot (circle) for very short strokes.
 */
function drawDot(center: Vec2, radius: number): Vec2[] {
  const offsetPoint = add(center, [1, 1])
  const start = prj(center, uni(per(sub(center, offsetPoint))), -radius)
  const dotPts: Vec2[] = []
  const step = 1 / START_CAP_SEGMENTS
  for (let t = step; t <= 1; t += step) {
    dotPts.push(rotAround(start, center, FIXED_PI * 2 * t))
  }
  return dotPts
}

/**
 * Draw a rounded start cap by rotating points from right to left around the start point.
 */
function drawRoundStartCap(
  center: Vec2,
  rightPoint: Vec2,
  segments: number
): Vec2[] {
  const cap: Vec2[] = []
  const step = 1 / segments
  for (let t = step; t <= 1; t += step) {
    cap.push(rotAround(rightPoint, center, FIXED_PI * t))
  }
  return cap
}

/**
 * Draw a flat start cap with squared-off edges.
 */
function drawFlatStartCap(
  center: Vec2,
  leftPoint: Vec2,
  rightPoint: Vec2
): Vec2[] {
  const cornersVector = sub(leftPoint, rightPoint)
  const offsetA = mul(cornersVector, 0.5)
  const offsetB = mul(cornersVector, 0.51)
  return [
    sub(center, offsetA),
    sub(center, offsetB),
    add(center, offsetB),
    add(center, offsetA),
  ]
}

/**
 * Draw a rounded end cap (1.5 turns to handle sharp end turns correctly).
 */
function drawRoundEndCap(
  center: Vec2,
  direction: Vec2,
  radius: number,
  segments: number
): Vec2[] {
  const cap: Vec2[] = []
  const start = prj(center, direction, radius)
  const step = 1 / segments
  for (let t = step; t < 1; t += step) {
    cap.push(rotAround(start, center, FIXED_PI * 3 * t))
  }
  return cap
}

/**
 * Draw a flat end cap with squared-off edges.
 */
function drawFlatEndCap(center: Vec2, direction: Vec2, radius: number): Vec2[] {
  return [
    add(center, mul(direction, radius)),
    add(center, mul(direction, radius * 0.99)),
    sub(center, mul(direction, radius * 0.99)),
    sub(center, mul(direction, radius)),
